module top (
  output [6:0] o,
  input clk,
  input signed [5:0] w6,
  input [8:0] w9
);

function lsb;
    input signed [5:0] i;
    lsb = i[0:0];
endfunction

  wire signed [5:0] lsb_w6;
  reg signed [5:0] r6;
  assign o = {lsb(^~w9), lsb_w6};
  assign lsb_w6 = lsb(w6);
  always @(posedge clk) begin
    r6 <= {{$unsigned(w9[2:1])}};
  end
endmodule
